import{_ as e,o as s,c as t,ag as o}from"./chunks/framework.CAXxHpAX.js";const h=JSON.parse('{"title":"什么是 Base URL","description":"","frontmatter":{},"headers":[],"relativePath":"guide/base-url.md","filePath":"guide/base-url.md"}'),l={name:"guide/base-url.md"};function i(r,a,n,d,u,p){return s(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="什么是-base-url" tabindex="-1">什么是 Base URL <a class="header-anchor" href="#什么是-base-url" aria-label="Permalink to &quot;什么是 Base URL&quot;">​</a></h1><p>Base URL 是 API 请求的基础地址,相当于你告诉工具&quot;去哪里调用 API&quot;。</p><h2 id="为什么需要自定义-base-url" tabindex="-1">为什么需要自定义 Base URL <a class="header-anchor" href="#为什么需要自定义-base-url" aria-label="Permalink to &quot;为什么需要自定义 Base URL&quot;">​</a></h2><p>默认情况下,大多数工具会使用官方 API 地址。但有时你需要自定义 Base URL:</p><ul><li><strong>使用代理或中转服务</strong>:通过第三方服务访问 API</li><li><strong>使用自建服务</strong>:调用自己部署的 API 服务</li><li><strong>使用兼容接口</strong>:某些工具支持 OpenAI 兼容接口,你可以指向其他服务商</li></ul><h2 id="base-url-的常见形式" tabindex="-1">Base URL 的常见形式 <a class="header-anchor" href="#base-url-的常见形式" aria-label="Permalink to &quot;Base URL 的常见形式&quot;">​</a></h2><p>Base URL 通常是一个 HTTPS 地址,例如:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://api.1010101.asia/</span></span></code></pre></div><p>或带路径的形式:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://api.example.com/v1</span></span></code></pre></div><h2 id="本文档站的默认-base-url" tabindex="-1">本文档站的默认 Base URL <a class="header-anchor" href="#本文档站的默认-base-url" aria-label="Permalink to &quot;本文档站的默认 Base URL&quot;">​</a></h2><p>本文档站以 <code>https://api.1010101.asia/</code> 作为示例 Base URL。你可以在工具配置页面中看到如何填写这个地址。</p><h2 id="在工具中填写-base-url" tabindex="-1">在工具中填写 Base URL <a class="header-anchor" href="#在工具中填写-base-url" aria-label="Permalink to &quot;在工具中填写 Base URL&quot;">​</a></h2><p>不同工具填写 Base URL 的位置不同,但通常在以下位置之一:</p><ul><li>设置面板的&quot;Base URL&quot;或&quot;API Endpoint&quot;字段</li><li>配置文件的 <code>baseURL</code> 或 <code>apiBase</code> 字段</li><li>环境变量(如 <code>ANTHROPIC_BASE_URL</code>)</li></ul><p>具体填写方式请参考对应工具的配置页面。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="base-url-填错了会怎样" tabindex="-1">Base URL 填错了会怎样? <a class="header-anchor" href="#base-url-填错了会怎样" aria-label="Permalink to &quot;Base URL 填错了会怎样?&quot;">​</a></h3><p>通常会返回 <code>404 Not Found</code> 或连接超时错误。</p><h3 id="base-url-需要以-结尾吗" tabindex="-1">Base URL 需要以 <code>/</code> 结尾吗? <a class="header-anchor" href="#base-url-需要以-结尾吗" aria-label="Permalink to &quot;Base URL 需要以 `/` 结尾吗?&quot;">​</a></h3><p>取决于服务商的 API 设计。本示例 <code>https://api.1010101.asia/</code> 以 <code>/</code> 结尾,请按工具页示例填写。</p><h3 id="base-url-和-api-key-有什么区别" tabindex="-1">Base URL 和 API Key 有什么区别? <a class="header-anchor" href="#base-url-和-api-key-有什么区别" aria-label="Permalink to &quot;Base URL 和 API Key 有什么区别?&quot;">​</a></h3><ul><li><strong>API Key</strong>:身份验证,相当于&quot;密码&quot;</li><li><strong>Base URL</strong>:请求地址,相当于&quot;服务器地址&quot;</li></ul><p>两者缺一不可:没有 API Key,服务器不认识你;没有 Base URL,工具不知道去哪里调用。</p>',24)])])}const b=e(l,[["render",i]]);export{h as __pageData,b as default};
